var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"세상엔 소원을 이뤄주는 일곱 요정이 있다고 해요.","JPN":"この世には願いを叶えてくれる七人の妖精がいるそうです。","ENG":"People say there are seven fairies that grant wishes.","TWN":"聽說世界上有七個可以替人完成願望的精靈。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"요정들은 가장 위대한 사람들 곁에 머물며, 소원을 하나씩 이뤄줬대요.","JPN":"彼らは最も偉大な人間の元に訪れ、願いを1つずつ叶えてくれたとか。","ENG":"These fairies reside by the greatest people and grant their wishes one by one.","TWN":"精靈會停留在最偉大的人身邊，為他一一實現願望。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"사람들은 요정이 옛날 이야기일 뿐이라 하지만…","JPN":"人々は妖精なんかおとぎ話の存在でしかないと言いますが……","ENG":"People say that fairies are all old folktales, but...","TWN":"大家都認為精靈只是神話故事…"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"전 요정이 아직 어딘가에 있다고 믿고 싶어요.","JPN":"私は妖精がまだどこかに存在していると信じたいのです。","ENG":"I want to believe that fairies are still out there somewhere.","TWN":"但我相信，精靈一定就在世界的某個地方。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"저도 요정님에게 위대한 사람으로 인정받아서… 꼭 빌고 싶은 소원이 있거든요.","JPN":"私も妖精さんから偉大な人間として認められて……ぜひ叶えてもらいたい願いがあるんです。","ENG":"Because I want to be recognized as one of the greatest... and have my wish come true.","TWN":"我也要成為偉大的人，得到精靈的認可。因為…我有必須實現的願望。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"먹을 거 사왔어요. 엄마.","JPN":"食べ物を買ってきたよ、お母さん。","ENG":"I brought food, Mommy.","TWN":"媽媽，我買吃的回來了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"고생했구나.","JPN":"あら、ご苦労様。","ENG":"You did a good job.","TWN":"辛苦你了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"이번엔 달걀도 사온 거니?","JPN":"今日もタマゴを買ってきたのかしら？","ENG":"Did you buy eggs this time?","TWN":"你有買雞蛋嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"네! 엄마가 해주는 오믈렛. 세상에서 제일 좋아하니까요.","JPN":"うん！　お母さんのオムレツが世界で一番美味しいから。","ENG":"Yup! Because the omelets you make are my favorite thing in the world.","TWN":"當然有！我最喜歡媽媽做的歐姆蛋了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"후후… 우리 딸 생일인데, 원한다면 당연히 해줘야지.","JPN":"ふふ……あなたの誕生日なんだし、もちろん作るわよ。","ENG":"Haha... Since it's your birthday, of course, I should make what you like the most.","TWN":"呵呵…我的乖女兒生日，想吃什麼媽媽當然要做給你吃囉。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"오는 길에 눈에 띄지는 않았고?","JPN":"それと、家に帰ってくるとき、誰かに見られたりしなかった？","ENG":"Did anyone notice you while you were out?","TWN":"回來的路上沒有被人發現吧？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"응, 늘 같이 다니던 골목으로 갔더니 아무한테도 안 들켰어요.","JPN":"うん、いつもの路地裏を通ってきたから、誰にも見つかっていないよ。","ENG":"Nope. I wasn't seen by anyone because I used the alley we always use.","TWN":"沒有，我走同一條路回來的，沒有被人發現。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"근데, 다녀오는 길에 제 또래의 아이들을 봤어요.","JPN":"でも、途中で私と同じぐらいの子どもたちがいて","ENG":"But I saw some kids my age on my way back.","TWN":"不果我回來的時候，有看到幾個和我同年紀的小孩。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"순례단의 용사들 놀이를 하고 있는데, 재밌어 보이더라고요.","JPN":"巡礼団の勇者ごっこをしていて、すごく楽しそうだった。","ENG":"They were playing as pilgrim heroes, and it looked fun.","TWN":"他們假扮成朝聖團的勇士在玩，感覺好好玩。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"금발의 여자애가 에클레시아님 역할을 맡았는데… 목검 하나로 엄청 멋지게 마왕을 물리쳤어요!","JPN":"そこにいた金髪の女の子がエクレシア様のマネをしていて、木刀で魔王を倒すところがすごくかっこよかったの！","ENG":"The blonde-haired girl played the role of Miss Ecclesia... and she defeated the Demon Lord with just one wooden sword!","TWN":"金頭髮的小女生扮成艾可露西亞…拿著一把木劍劈向魔王，超帥的！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"하마터면 박수를 칠 뻔했다니까요?","JPN":"思わず拍手しそうになったけど、我慢したよ。","ENG":"I almost started clapping when I saw that.","TWN":"我還差一點要鼓掌叫好欸？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"그 애들이… 너에게 말을 걸었니?","JPN":"その子たちに……声をかけられたの？","ENG":"Those kids... did they talk to you?","TWN":"他們…有跟你說話嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"음… 아뇨.","JPN":"うーん……かけられてない。","ENG":"Um... no.","TWN":"嗯…沒有。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"잠깐 구경만 하다가 왔어요.","JPN":"私が一方的に見ていただけ。","ENG":"I just watched them for a bit then left.","TWN":"我在旁邊看一下就走了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제가 있는 줄도 몰랐을 거예요.","JPN":"私のことなんて気づいていなかったと思うわ。","ENG":"I'm sure they didn't even know I was looking.","TWN":"他們應該沒發覺我的存在。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"그래… 잘 했구나.","JPN":"そう……わかったわ。","ENG":"Okay... You did good.","TWN":"是嗎…那就好。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"그런데 엄마.","JPN":"ところでお母さん。","ENG":"But Mommy?","TWN":"媽媽，"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"우리 언제까지 이렇게 숨어 지내야 해요?","JPN":"いったいいつまで私たちは隠れながら暮らさないといけないの？","ENG":"How much longer do we have to stay hidden?","TWN":"我們要這樣躲到什麼時候？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"우리가 숨어 살아야 할 정도로 나쁜 죄를 지었나요?","JPN":"人目についちゃいけないほど、重罪を犯したの？","ENG":"Did we do something so bad that we have to live in hiding?","TWN":"我們做了什麼十惡不赦的壞事，所以才必須這樣躲躲藏藏的嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"POOR_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"미안하구나, 아가.","JPN":"本当にごめんね。","ENG":"I'm sorry, my child.","TWN":"媽媽對不起你。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"이렇게 된 건…","JPN":"こうなったのは……","ENG":"It's all my fault...","TWN":"都怪媽媽不好…"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SICK_ROOT_NPC_NULL","text":{"KOREA":"전부 내 잘못이야.","JPN":"全部私のせいなの。","ENG":"that we're living like this.","TWN":"害你必須過這種日子。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};